<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';$portal=portalEstudianteCabecera('Mis capacitaciones','cursos','Cursos en los que tu cuenta tiene una matrícula académica activa.');$pdo=obtenerConexion();$q=$pdo->prepare("SELECT a.id,a.codigo,a.nombre,a.descripcion,CONCAT_WS(' ',d.nombre,d.apellido) docente FROM estudiantes_docentes ed JOIN asignaturas a ON a.id=ed.asignatura_id JOIN usuarios d ON d.id=ed.docente_id JOIN docentes_asignaturas da ON da.docente_id=ed.docente_id AND da.asignatura_id=ed.asignatura_id AND da.estado='activo' WHERE ed.estudiante_id=:u AND ed.estado='activo' AND a.estado='activo' AND d.estado='activo' AND d.deleted_at IS NULL ORDER BY a.nombre");$q->execute(['u'=>$_SESSION['usuario_id']]);$cursos=$q->fetchAll();?>
<div class="row"><?php foreach($cursos as$c):?><div class="col-md-6"><div class="card"><div class="card-body"><span class="badge bg-primary"><?=atenea_e($c['codigo'])?></span><h2 class="h4 mt-3"><?=atenea_e($c['nombre'])?></h2><p class="text-muted"><?=atenea_e((string)$c['descripcion'])?></p><p><i class="bi bi-person-video3"></i> <?=atenea_e($c['docente'])?></p><a class="btn btn-primary" href="curso.php?id=<?=$c['id']?>">Abrir curso</a></div></div></div><?php endforeach;?><?php if(!$cursos):?><div class="col-12"><div class="card"><div class="card-body text-center py-5"><i class="bi bi-journal-bookmark display-3 text-primary"></i><h2 class="h4 mt-3">No hay capacitaciones asignadas</h2><p class="text-muted mb-0">Tu cuenta no tiene matrículas académicas activas.</p></div></div></div><?php endif;?></div><?php portalEstudiantePie();
